// Aguarda os dois ramos e une os dados para análise pelo Gemini
const grasp_data = $('GRASP (50 execuções)').first().json;
const ag_data    = $('Algoritmo Genético (50 execuções)').first().json;

return [{
  json: {
    grasp:      grasp_data.execucoes || [],
    genetico:   ag_data.execucoes   || [],
    total_grasp: grasp_data.total   || 0,
    total_ag:    ag_data.total      || 0
  }
}];

const graficos = $input.first().json;

return [{
  json: {
    pipeline_status: graficos.status === 'sucesso'
      ? 'PIPELINE COMPLETO — Trabalho 2 (GRASP + AG)'
      : 'CONCLUÍDO COM AVISOS — verifique erros',
    arquivos_gerados: [
      'resultados/execucoes_grasp.csv',
      'resultados/execucoes_genetico.csv',
      'resultados/metricas_gemini.json',
      'resultados/comp_grafico1_taxa_sucesso.png',
      'resultados/comp_grafico2_tempo_execucao.png',
      'resultados/comp_grafico3_iteracoes_geracoes.png',
      'resultados/comp_grafico4_hfinal_execucoes.png',
      'resultados/comp_tabela_resumo_estatistico.png',
      'resultados/comp_tabela_top5_ag.png'
    ],
    erros:  graficos.erros || [],
    log:    (graficos.log || '').slice(0, 500)
  }
}];
